   251→    );
   252→  }
   253→
   254→  if (columns.length === 0) {
   255→    return (
   256→      <div className={outerClass}>
   257→        <div className="flex flex-col items-center justify-center h-full px-4 text-center">
   258→          <h3 className="text-section-title font-semibold text-foreground mb-2">
