   640→      salonTimezone,
   641→      "yyyy-MM-dd"
   642→    );
   643→    const selectedDateStr = formatInTimeZone(
   644→      selectedDate,
   645→      salonTimezone,
   646→      "yyyy-MM-dd"
   647→    );
   648→
   649→    return selectedDateStr === todayInSalonTz;
   650→  }, [selectedDate, salonTimezone]);
   651→
   652→  // Update current time every minute when viewing today
   653→  useEffect(() => {
   654→    if (!isTodayDate) return;
   655→
   656→    const interval = setInterval(() => {
   657→      setCurrentTime(new Date());
   658→    }, 60000); // Update every minute
   659→
   660→    return () => clearInterval(interval);
   661→  }, [isTodayDate]);
   662→
   663→  const handleSlotClick = (
   664→    slot: TimeSlot,
   665→    event: React.MouseEvent<HTMLDivElement>
   666→  ): void => {
   667→    const blockStatus = isSlotBlocked(
   668→      slot,
   669→      professional.breaks,
   670→      isPastDay,
   671→      professionalSchedule,
   672→      selectedDate,
   673→      salonIsOpen,
   674→      salonTimezone,
   675→      slotDurationMinutes
   676→    );
   677→
   678→    // Criterion 5: Disabled cells should not receive click events
   679→    if (blockStatus.blocked) {
   680→      return;
   681→    }
   682→
   683→    const rect = event.currentTarget.getBoundingClientRect();
   684→    setClickedSlot({
   685→      slot,
   686→      x: rect.left,
   687→      y: rect.top + rect.height,
