   800→        const startMinute = startTime.minutes;
   801→        const endHour = endTime.hours;
   802→        const endMinute = endTime.minutes;
   803→
   804→        const startMinutesTotal = startHour * 60 + startMinute;
   805→        const endMinutesTotal = endHour * 60 + endMinute;
   806→
   807→        // Calculate position from first slot
   808→        const startMinutesFromFirst = startMinutesTotal - firstSlotMinutes;
   809→        const durationMinutes = endMinutesTotal - startMinutesTotal;
   810→
   811→        // Calculate top and height ensuring pixel-perfect alignment
   812→        // Round to ensure alignment with slot boundaries
   813→        let top = Math.round(
   814→          (startMinutesFromFirst / slotMinutes) * slotHeight
   815→        );
   816→        let height = Math.round((durationMinutes / slotMinutes) * slotHeight);
   817→
   818→        // Clamp to visible area
   819→        if (top < 0) {
   820→          height += top;
   821→          top = 0;
   822→        }
   823→
   824→        if (top + height > maxVisibleHeight) {
   825→          height = maxVisibleHeight - top;
   826→        }
   827→
   828→        const startTimeStr = `${startHour
   829→          .toString()
