   136→type GetScheduleBreaksParams = {
   137→  professional: User;
   138→  selectedDate: Date;
   139→  salonTimezone: string;
   140→};
   141→
   142→type ScheduleBreakResult = {
   143→  id: string;
   144→  start: string;
   145→  end: string;
   146→  type: "ausencia" | "indisponibilidade";
   147→  reason?: string;
   148→};
   149→
   150→const getScheduleBreaksForDate = ({
   151→  professional,
   152→  selectedDate,
   153→  salonTimezone,
   154→}: GetScheduleBreaksParams): ScheduleBreakResult[] => {
   155→  if (!professional.schedule) {
   156→    return [];
   157→  }
   158→
   159→  // Normalize schedule to handle both numeric keys and day names
   160→  const normalizedSchedule = normalizeSchedule(professional.schedule);
   161→  if (!normalizedSchedule) {
   162→    return [];
   163→  }
   164→
   165→  const dayOfWeek = selectedDate.getUTCDay();
   166→  const dayMap: Record<number, keyof typeof normalizedSchedule> = {
   167→    0: "sunday",
   168→    1: "monday",
   169→    2: "tuesday",
   170→    3: "wednesday",
   171→    4: "thursday",
   172→    5: "friday",
   173→    6: "saturday",
   174→  };
   175→
   176→  const dayName = dayMap[dayOfWeek];
   177→  const daySchedule = normalizedSchedule[dayName];
   178→
   179→  if (!daySchedule?.breaks || daySchedule.breaks.length === 0) {
   180→    return [];
   181→  }
   182→
   183→  const dateString = format(selectedDate, "yyyy-MM-dd");
   184→  const breaks = daySchedule.breaks.map(
   185→    (breakPeriod: { start: string; end: string }, index: number) => {
   186→      const startLocal = `${dateString}T${breakPeriod.start}:00`;
   187→      const endLocal = `${dateString}T${breakPeriod.end}:00`;
   188→
   189→      const startUTC = fromZonedTime(startLocal, salonTimezone);
   190→      const endUTC = fromZonedTime(endLocal, salonTimezone);
   191→
   192→      return {
   193→        id: `schedule-break-${professional.id}-${dayOfWeek}-${index}`,
   194→        start: startUTC.toISOString(),
   195→        end: endUTC.toISOString(),
   196→        type: "indisponibilidade" as const,
   197→        reason: "Intervalo de descanso",
   198→      };
   199→    }
   200→  );
   201→
   202→  return breaks;
   203→};
