     7→interface EventBlockProps {
     8→  event: CalendarEvent;
     9→  position: EventPosition;
    10→  layout?: { column: number; totalColumns: number };
    11→  primaryColor?: string;
    12→  salonTimezone?: string;
    13→  onClick?: (event: CalendarEvent) => void;
    14→  isHighlighted?: boolean;
    15→}
    16→
    17→interface EventStyleConfig {
    18→  bgColor: string;
    19→  borderColor: string;
    20→  textColor: string;
    21→}
    22→
    23→const getEventStyles = (
    24→  variant?: string,
    25→  status?: string,
    26→  primaryColor?: string
    27→): EventStyleConfig => {
    28→  // Ausência sempre vermelho
    29→  if (variant === "ausencia") {
    30→    return {
    31→      bgColor: "bg-red-50",
    32→      borderColor: "border-l-red-500",
    33→      textColor: "text-red-900",
    34→    };
    35→  }
    36→
    37→  // Reserva sempre roxo
    38→  if (variant === "reserva") {
    39→    return {
    40→      bgColor: "bg-purple-50",
    41→      borderColor: "border-l-purple-500",
    42→      textColor: "text-purple-900",
    43→    };
    44→  }
    45→
    46→  // Status-based colors
    47→  if (status === "Atendendo") {
    48→    return {
    49→      bgColor: "bg-blue-50",
    50→      borderColor: "border-l-blue-500",
    51→      textColor: "text-blue-900",
    52→    };
    53→  }
    54→  if (status === "Pgto Pendente") {
    55→    return {
    56→      bgColor: "bg-yellow-50",
    57→      borderColor: "border-l-yellow-500",
    58→      textColor: "text-yellow-900",
    59→    };
    60→  }
    61→  if (status === "Pago") {
    62→    return {
    63→      bgColor: "bg-green-50",
    64→      borderColor: "border-l-green-500",
    65→      textColor: "text-green-900",
    66→    };
    67→  }
    68→  if (status === "Cancelado") {
    69→    return {
    70→      bgColor: "bg-muted",
    71→      borderColor: "border-l-muted-foreground",
    72→      textColor: "text-muted-foreground",
    73→    };
    74→  }
    75→
    76→  // Default - usa cor do salão ou token do tema
    77→  return {
    78→    bgColor: "bg-card",
    79→    borderColor: primaryColor ? "" : "border-l-foreground",
    80→    textColor: "text-foreground",
    81→  };
    82→};
    83→
    84→const formatTime = (dateStr: string, timezone: string): string => {
    85→  // Converter UTC para timezone do salão
    86→  return formatUTCToLocal(dateStr, timezone, 'HH:mm');
    87→};
    88→
    89→export const EventBlock: React.FC<EventBlockProps> = ({
    90→  event,
    91→  position,
    92→  layout,
    93→  primaryColor,
    94→  salonTimezone = "America/Sao_Paulo",
    95→  onClick,
    96→  isHighlighted = false,
    97→}) => {
    98→  const styles = getEventStyles(event.variant, event.status, primaryColor);
    99→  const isReserva = event.variant === "reserva";
   100→
   101→  const minHeight = 50; // Minimum height in pixels (aligned with SLOT_HEIGHT for 15 min slots)
   102→  const eventHeight = Math.max(position.height, minHeight);
   103→
   104→  // Calcula posicionamento e largura baseado no layout
   105→  const layoutStyles = layout ? {
   106→    left: `${(layout.column / layout.totalColumns) * 100}%`,
   107→    width: `calc(${100 / layout.totalColumns}% - 4px)`,
   108→  } : {
   109→    left: '4px',
   110→    right: '4px',
   111→  };
   112→
   113→  // Ajusta padding quando o evento está comprimido
   114→  const isCompressed = layout && layout.totalColumns > 1;
   115→  const paddingClass = isCompressed && layout.totalColumns >= 3 ? "px-1 py-0.5" : "px-2 py-1";
   116→
   117→  return (
   118→    <div
   119→      className={cn(
   120→        "absolute rounded-sm shadow-sm cursor-pointer",
   121→        "hover:shadow-md transition-shadow duration-150",
   122→        paddingClass,
   123→        "overflow-hidden border-l-4",
   124→        styles.bgColor,
   125→        styles.borderColor,
   126→        styles.textColor,
   127→        isHighlighted && "ring-2 ring-blue-500 ring-offset-1 z-30"
   128→      )}
   129→      style={{
   130→        top: `${position.top}px`,
   131→        height: `${eventHeight}px`,
   132→        minHeight: `${minHeight}px`,
   133→        ...layoutStyles,
   134→        ...(primaryColor && !styles.borderColor
   135→          ? { borderLeftColor: primaryColor }
   136→          : {}),
   137→      }}
   138→      onClick={() => onClick?.(event)}
   139→      title={isCompressed ? `${event.clientName} - ${event.serviceName}` : undefined}
   140→    >
   141→      {/* Ping overlay — visível apenas quando highlighted */}
   142→      {isHighlighted && (
   143→        <span className="absolute inset-0 rounded-md ring-2 ring-blue-400 animate-ping opacity-75 pointer-events-none z-0" />
   144→      )}
   145→
   146→      <div className="relative z-10 h-full">
   147→      {isReserva ? (
   148→        <div className="flex flex-col h-full justify-center items-center">
   149→          <span className="font-bold text-body text-center">Reserva feita pelo profissional</span>
   150→          <div className="flex items-center gap-1 text-[10px] opacity-80 mt-1">
   151→            <Clock className="w-3 h-3" />
   152→            <span>
   153→              {formatTime(event.start, salonTimezone)} -{" "}
   154→              {formatTime(event.end, salonTimezone)}
   155→            </span>
   156→          </div>
   157→        </div>
   158→      ) : (
   159→        <div className="flex flex-col h-full text-button">
   160→          <div className="flex items-center justify-between gap-1">
   161→            <span className="font-semibold text-body truncate">{event.clientName}</span>
   162→            {event.source && (
   163→              <BookingSourceBadge
   164→                source={event.source}
   165→                className="flex-shrink-0 text-[9px] px-1 py-0.5"
   166→              />
   167→            )}
   168→          </div>
   169→          <div className="flex items-center gap-1 text-[10px] opacity-80">
   170→            <Clock className="w-3 h-3" />
   171→            <span>
   172→              {formatTime(event.start, salonTimezone)} -{" "}
   173→              {formatTime(event.end, salonTimezone)}
   174→            </span>
   175→          </div>
   176→          <div className="text-[10px] truncate opacity-70">
   177→            {event.serviceName}
   178→          </div>
   179→        </div>
   180→      )}
   181→      </div>
   182→    </div>
   183→  );
   184→};
